import { Component, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup, UntypedFormArray, UntypedFormControl } from '@angular/forms';
import { fadeInUp400ms } from '../../../../ux/animations/fade-in-up.animation';
import { MAT_FORM_FIELD_DEFAULT_OPTIONS, MatFormFieldDefaultOptions } from '@angular/material/form-field';
import { CmsService } from '../cms.service';
import { Subscription } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';

@Component({
  selector: 'ux-cms-villagemuseums-page',
  templateUrl: './cms-villagemuseums-page.component.html',
  styleUrls: ['./cms-villagemuseums-page.component.scss'],
  animations: [fadeInUp400ms],
  providers: [
    {
      provide: MAT_FORM_FIELD_DEFAULT_OPTIONS,
      useValue: {
        appearance: 'standard'
      } as MatFormFieldDefaultOptions
    }
  ]
})
export class CmsVillageMuseumsPageComponent implements OnInit {
  layoutCtrl = new UntypedFormControl('fullwidth');
  form: UntypedFormGroup;
  existingId: string = '';
  subscription: Subscription;

  constructor(
    private fb: UntypedFormBuilder,
    private cmsService: CmsService,
    private authService: AuthService
  ) { }

  ngOnInit() {
    this.buildForm();

    this.subscription = this.cmsService.villagemuseums_listChanged
      .subscribe((list: any[]) => {
        if (list && list.length > 0) {
          this.populateForm(list[0]);
        }
      });

    const list = this.cmsService.getVillageMuseumsList();
    if (list && list.length > 0) {
      this.populateForm(list[0]);
    }
  }

  private buildForm() {
    this.form = this.fb.group({
      title: '',
      description1: '',
      description2: '',
      status: '1',
      locations: this.fb.array([])
    });
  }

  private populateForm(data: any) {
    this.existingId = data._id || '';
    this.form.patchValue({
      title: data.title || '',
      description1: data.description1 || '',
      description2: data.description2 || '',
      status: data.status || '1'
    });

    this.locations.clear();
    (data.locations || []).forEach((location: any) => this.addLocation(location));
  }

  get locations(): UntypedFormArray {
    return this.form.get('locations') as UntypedFormArray;
  }

  addLocation(location?: any) {
    const locationGroup = this.fb.group({
      name: location?.name || '',
      image: location?.image || '',
      description: location?.description || '',
      activities: this.fb.array([])
    });

    if (location?.activities) {
      const activitiesArray = locationGroup.get('activities') as UntypedFormArray;
      location.activities.forEach((activity: any) => {
        activitiesArray.push(this.fb.group({
          name: activity.name || '',
          image: activity.image || ''
        }));
      });
    }

    this.locations.push(locationGroup);
  }

  removeLocation(index: number) {
    this.locations.removeAt(index);
  }

  getActivities(locationIndex: number): UntypedFormArray {
    return this.locations.at(locationIndex).get('activities') as UntypedFormArray;
  }

  addActivity(locationIndex: number) {
    const activities = this.getActivities(locationIndex);
    activities.push(this.fb.group({
      name: '',
      image: ''
    }));
  }

  removeActivity(locationIndex: number, activityIndex: number) {
    const activities = this.getActivities(locationIndex);
    activities.removeAt(activityIndex);
  }

  save() {
    const data = this.form.value;
    data.villagemuseums_id = this.existingId || '';
    data.loggedin_id = this.authService.getLoggedInID();
    data.status = data.status || '1';
    this.cmsService.saveVillageMuseums(data);
  }
}
