import { Component, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup, UntypedFormArray, UntypedFormControl } from '@angular/forms';
import { fadeInUp400ms } from '../../../../ux/animations/fade-in-up.animation';
import { MAT_FORM_FIELD_DEFAULT_OPTIONS, MatFormFieldDefaultOptions } from '@angular/material/form-field';
import { CmsService } from '../cms.service';
import { Subscription } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';

@Component({
  selector: 'ux-cms-exhibitions-page',
  templateUrl: './cms-exhibitions-page.component.html',
  styleUrls: ['./cms-exhibitions-page.component.scss'],
  animations: [fadeInUp400ms],
  providers: [
    {
      provide: MAT_FORM_FIELD_DEFAULT_OPTIONS,
      useValue: {
        appearance: 'standard'
      } as MatFormFieldDefaultOptions
    }
  ]
})
export class CmsExhibitionsPageComponent implements OnInit {
  layoutCtrl = new UntypedFormControl('fullwidth');
  form: UntypedFormGroup;
  existingId: string = '';
  subscription: Subscription;

  constructor(
    private fb: UntypedFormBuilder,
    private cmsService: CmsService,
    private authService: AuthService
  ) { }

  ngOnInit() {
    this.buildForm();

    this.subscription = this.cmsService.exhibitions_listChanged
      .subscribe((list: any[]) => {
        if (list && list.length > 0) {
          this.populateForm(list[0]);
        }
      });

    const list = this.cmsService.getExhibitionsList();
    if (list && list.length > 0) {
      this.populateForm(list[0]);
    }
  }

  private buildForm() {
    this.form = this.fb.group({
      title: '',
      description: '',
      status: '1',
      years: this.fb.array([])
    });
  }

  private populateForm(data: any) {
    this.existingId = data._id || '';
    this.form.patchValue({
      title: data.title || '',
      description: data.description || '',
      status: data.status || '1'
    });

    this.years.clear();
    (data.years || []).forEach((year: any) => this.addYear(year));
  }

  get years(): UntypedFormArray {
    return this.form.get('years') as UntypedFormArray;
  }

  addYear(year?: any) {
    const yearGroup = this.fb.group({
      exhibition_year: year?.exhibition_year || '',
      exhibitions: this.fb.array([])
    });

    if (year?.exhibitions) {
      const exhibitionsArray = yearGroup.get('exhibitions') as UntypedFormArray;
      year.exhibitions.forEach((exhibition: any) => {
        exhibitionsArray.push(this.fb.group({
          title: exhibition.title || '',
          title_image: exhibition.title_image || '',
          images: this.fb.array(exhibition.images?.map((img: string) => this.fb.control(img)) || [])
        }));
      });
    }

    this.years.push(yearGroup);
  }

  removeYear(index: number) {
    this.years.removeAt(index);
  }

  getExhibitions(yearIndex: number): UntypedFormArray {
    return this.years.at(yearIndex).get('exhibitions') as UntypedFormArray;
  }

  addExhibition(yearIndex: number) {
    const exhibitions = this.getExhibitions(yearIndex);
    exhibitions.push(this.fb.group({
      title: '',
      title_image: '',
      images: this.fb.array([])
    }));
  }

  removeExhibition(yearIndex: number, exhibitionIndex: number) {
    const exhibitions = this.getExhibitions(yearIndex);
    exhibitions.removeAt(exhibitionIndex);
  }

  getImages(yearIndex: number, exhibitionIndex: number): UntypedFormArray {
    const exhibitions = this.getExhibitions(yearIndex);
    return exhibitions.at(exhibitionIndex).get('images') as UntypedFormArray;
  }

  addImage(yearIndex: number, exhibitionIndex: number) {
    const images = this.getImages(yearIndex, exhibitionIndex);
    images.push(this.fb.control(''));
  }

  removeImage(yearIndex: number, exhibitionIndex: number, imageIndex: number) {
    const images = this.getImages(yearIndex, exhibitionIndex);
    images.removeAt(imageIndex);
  }

  save() {
    const data = this.form.value;
    data.exhibitions_id = this.existingId || '';
    data.loggedin_id = this.authService.getLoggedInID();
    data.status = data.status || '1';
    this.cmsService.saveExhibitions(data);
  }
}
