import { Component, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup, UntypedFormArray, UntypedFormControl } from '@angular/forms';
import { fadeInUp400ms } from '../../../../ux/animations/fade-in-up.animation';
import { MAT_FORM_FIELD_DEFAULT_OPTIONS, MatFormFieldDefaultOptions } from '@angular/material/form-field';
import { CmsService } from '../cms.service';
import { Subscription } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';

@Component({
  selector: 'ux-cms-handicrafts-page',
  templateUrl: './cms-handicrafts-page.component.html',
  styleUrls: ['./cms-handicrafts-page.component.scss'],
  animations: [fadeInUp400ms],
  providers: [
    {
      provide: MAT_FORM_FIELD_DEFAULT_OPTIONS,
      useValue: {
        appearance: 'standard'
      } as MatFormFieldDefaultOptions
    }
  ]
})
export class CmsHandicraftsPageComponent implements OnInit {
  layoutCtrl = new UntypedFormControl('fullwidth');
  form: UntypedFormGroup;
  existingId: string = '';
  subscription: Subscription;

  constructor(
    private fb: UntypedFormBuilder,
    private cmsService: CmsService,
    private authService: AuthService
  ) { }

  ngOnInit() {
    this.buildForm();

    this.subscription = this.cmsService.handicrafts_listChanged
      .subscribe((list: any[]) => {
        if (list && list.length > 0) {
          this.populateForm(list[0]);
        }
      });

    const list = this.cmsService.getHandicraftsList();
    if (list && list.length > 0) {
      this.populateForm(list[0]);
    }
  }

  private buildForm() {
    this.form = this.fb.group({
      description: '',
      status: '1',
      gallery_sections: this.fb.array([])
    });
  }

  private populateForm(data: any) {
    this.existingId = data._id || '';
    this.form.patchValue({
      description: data.description || '',
      status: data.status || '1'
    });

    this.gallerySections.clear();
    (data.gallery_sections || []).forEach((section: any) => this.addSection(section));
  }

  // Gallery Sections
  get gallerySections(): UntypedFormArray {
    return this.form.get('gallery_sections') as UntypedFormArray;
  }

  addSection(section?: any) {
    const sectionGroup = this.fb.group({
      title: section?.title || '',
      sort_order: section?.sort_order || this.gallerySections.length,
      images: this.fb.array([])
    });

    this.gallerySections.push(sectionGroup);

    const sectionIndex = this.gallerySections.length - 1;
    if (section?.images && section.images.length > 0) {
      section.images.forEach((img: any) => this.addImage(sectionIndex, img));
    }
  }

  removeSection(index: number) {
    this.gallerySections.removeAt(index);
  }

  // Images within a section
  getSectionImages(sectionIndex: number): UntypedFormArray {
    return this.gallerySections.at(sectionIndex).get('images') as UntypedFormArray;
  }

  addImage(sectionIndex: number, img?: any) {
    this.getSectionImages(sectionIndex).push(this.fb.group({
      name: img?.name || '',
      image_path: img?.image_path || '',
      navigation_route: img?.navigation_route || '',
      sort_order: img?.sort_order || this.getSectionImages(sectionIndex).length
    }));
  }

  removeImage(sectionIndex: number, imageIndex: number) {
    this.getSectionImages(sectionIndex).removeAt(imageIndex);
  }

  save() {
    const data = this.form.value;
    data.handicrafts_id = this.existingId || '';
    data.loggedin_id = this.authService.getLoggedInID();
    data.status = data.status || '1';
    this.cmsService.saveHandicrafts(data);
  }
}
