import { NgModule } from '@angular/core';
import { RouterModule } from '@angular/router';
import { QuicklinkModule } from 'ngx-quicklink';
import { UxRoutes } from '../../../ux/interfaces/ux-route.interface';
import { CmsPageComponent } from './cms-page/cms-page.component';
import { CmsHandicraftsPageComponent } from './cms-handicrafts-page/cms-handicrafts-page.component';
import { CmsHandloomsPageComponent } from './cms-handlooms-page/cms-handlooms-page.component';
import { CmsFolkArtsPageComponent } from './cms-folkarts-page/cms-folkarts-page.component';
import { CmsCulturalEventsPageComponent } from './cms-culturalevents-page/cms-culturalevents-page.component';
import { CmsVillageMuseumsPageComponent } from './cms-villagemuseums-page/cms-villagemuseums-page.component';
import { CmsExhibitionsPageComponent } from './cms-exhibitions-page/cms-exhibitions-page.component';
import { CmsTendersPageComponent } from './cms-tenders-page/cms-tenders-page.component';
import { AboutUsResolverService, HandicraftsResolverService, HandloomsResolverService, FolkArtsResolverService, CulturalEventsResolverService, VillageMuseumsResolverService, ExhibitionsResolverService, TendersResolverService } from './cms-resolver.service';

const routes: UxRoutes = [
  {
    path: 'aboutus',
    component: CmsPageComponent,
    data: {
      toolbarShadowEnabled: false
    },
    resolve: [AboutUsResolverService]
  },
  {
    path: 'parks',
    component: CmsPageComponent,
    data: {
      toolbarShadowEnabled: false,
      pageType: 'parks'
    }
  },
  {
    path: 'handicrafts',
    component: CmsHandicraftsPageComponent,
    data: {
      toolbarShadowEnabled: false
    },
    resolve: [HandicraftsResolverService]
  },
  {
    path: 'handlooms',
    component: CmsHandloomsPageComponent,
    data: {
      toolbarShadowEnabled: false
    },
    resolve: [HandloomsResolverService]
  },
  {
    path: 'folkarts',
    component: CmsFolkArtsPageComponent,
    data: {
      toolbarShadowEnabled: false
    },
    resolve: [FolkArtsResolverService]
  },
  {
    path: 'culturalevents',
    component: CmsCulturalEventsPageComponent,
    data: {
      toolbarShadowEnabled: false
    },
    resolve: [CulturalEventsResolverService]
  },
  {
    path: 'villagemuseums',
    component: CmsVillageMuseumsPageComponent,
    data: {
      toolbarShadowEnabled: false
    },
    resolve: [VillageMuseumsResolverService]
  },
  {
    path: 'exhibitions',
    component: CmsExhibitionsPageComponent,
    data: {
      toolbarShadowEnabled: false
    },
    resolve: [ExhibitionsResolverService]
  },
  {
    path: 'tenders',
    component: CmsTendersPageComponent,
    data: {
      toolbarShadowEnabled: false
    },
    resolve: [TendersResolverService]
  }
];

@NgModule({
  imports: [RouterModule.forChild(routes)],
  exports: [RouterModule, QuicklinkModule]
})
export class CmsRoutingModule {
}
