import { Component, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup, UntypedFormArray, UntypedFormControl } from '@angular/forms';
import { fadeInUp400ms } from '../../../../ux/animations/fade-in-up.animation';
import { MAT_FORM_FIELD_DEFAULT_OPTIONS, MatFormFieldDefaultOptions } from '@angular/material/form-field';
import { CmsService } from '../cms.service';
import { Subscription } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';

@Component({
  selector: 'ux-cms-page',
  templateUrl: './cms-page.component.html',
  styleUrls: ['./cms-page.component.scss'],
  animations: [fadeInUp400ms],
  providers: [
    {
      provide: MAT_FORM_FIELD_DEFAULT_OPTIONS,
      useValue: {
        appearance: 'standard'
      } as MatFormFieldDefaultOptions
    }
  ]
})
export class CmsPageComponent implements OnInit {
  layoutCtrl = new UntypedFormControl('fullwidth');
  form: UntypedFormGroup;
  existingId: string = '';
  subscription: Subscription;

  constructor(
    private fb: UntypedFormBuilder,
    private cmsService: CmsService,
    private authService: AuthService
  ) { }

  ngOnInit() {
    this.buildForm();

    this.subscription = this.cmsService.aboutus_listChanged
      .subscribe((list: any[]) => {
        if (list && list.length > 0) {
          this.populateForm(list[0]);
        }
      });

    const list = this.cmsService.getAboutUsList();
    if (list && list.length > 0) {
      this.populateForm(list[0]);
    }
  }

  private buildForm() {
    this.form = this.fb.group({
      para1: '',
      para2: '',
      para3: '',
      para4: '',
      vision: '',
      status: '1',
      objectives: this.fb.array([]),
      mission: this.fb.array([]),
      members_list: this.fb.array([])
    });
  }

  private populateForm(data: any) {
    this.existingId = data._id || '';
    this.form.patchValue({
      para1: data.para1 || '',
      para2: data.para2 || '',
      para3: data.para3 || '',
      para4: data.para4 || '',
      vision: data.vision || '',
      status: data.status || '1'
    });

    // Clear and repopulate arrays
    this.objectives.clear();
    (data.objectives || []).forEach((obj: any) => this.addObjective(obj));

    this.missionList.clear();
    (data.mission || []).forEach((m: any) => this.addMission(m));

    this.membersList.clear();
    (data.members_list || []).forEach((member: any) => this.addMember(member));
  }

  // Objectives
  get objectives(): UntypedFormArray {
    return this.form.get('objectives') as UntypedFormArray;
  }

  addObjective(obj?: any) {
    this.objectives.push(this.fb.group({
      objective: obj?.objective || '',
      sort_order: obj?.sort_order || this.objectives.length
    }));
  }

  removeObjective(index: number) {
    this.objectives.removeAt(index);
  }

  // Mission
  get missionList(): UntypedFormArray {
    return this.form.get('mission') as UntypedFormArray;
  }

  addMission(m?: any) {
    this.missionList.push(this.fb.group({
      mission: m?.mission || '',
      sort_order: m?.sort_order || this.missionList.length
    }));
  }

  removeMission(index: number) {
    this.missionList.removeAt(index);
  }

  // Members
  get membersList(): UntypedFormArray {
    return this.form.get('members_list') as UntypedFormArray;
  }

  addMember(member?: any) {
    this.membersList.push(this.fb.group({
      name: member?.name || '',
      designation: member?.designation || '',
      image: member?.image || '',
      sort_order: member?.sort_order || this.membersList.length
    }));
  }

  removeMember(index: number) {
    this.membersList.removeAt(index);
  }

  save() {
    const data = this.form.value;
    data.aboutus_id = this.existingId || '';
    data.loggedin_id = this.authService.getLoggedInID();
    data.status = data.status || '1';
    this.cmsService.saveAboutUs(data);
  }
}
