import { Component, OnInit } from '@angular/core';
import { UntypedFormBuilder, UntypedFormGroup, UntypedFormArray } from '@angular/forms';
import { fadeInUp400ms } from '../../../../ux/animations/fade-in-up.animation';
import { MAT_FORM_FIELD_DEFAULT_OPTIONS, MatFormFieldDefaultOptions } from '@angular/material/form-field';
import { CmsService } from '../cms.service';
import { Subscription } from 'rxjs';
import { AuthService } from 'src/app/auth/auth.service';

@Component({
  selector: 'ux-cms-tenders-page',
  templateUrl: './cms-tenders-page.component.html',
  styleUrls: ['./cms-tenders-page.component.scss'],
  animations: [fadeInUp400ms],
  providers: [
    {
      provide: MAT_FORM_FIELD_DEFAULT_OPTIONS,
      useValue: {
        appearance: 'standard'
      } as MatFormFieldDefaultOptions
    }
  ]
})
export class CmsTendersPageComponent implements OnInit {
  form: UntypedFormGroup;
  existingId: string = '';
  subscription: Subscription;

  constructor(
    private fb: UntypedFormBuilder,
    private cmsService: CmsService,
    private authService: AuthService
  ) { }

  ngOnInit() {
    this.buildForm();

    this.subscription = this.cmsService.tenders_listChanged
      .subscribe((list: any[]) => {
        if (list && list.length > 0) {
          this.populateForm(list[0]);
        }
      });

    const list = this.cmsService.getTendersList();
    if (list && list.length > 0) {
      this.populateForm(list[0]);
    }
  }

  private buildForm() {
    this.form = this.fb.group({
      page_title: '',
      page_description: '',
      status: '1',
      tenders: this.fb.array([])
    });
  }

  private populateForm(data: any) {
    this.existingId = data._id || '';
    this.form.patchValue({
      page_title: data.page_title || '',
      page_description: data.page_description || '',
      status: data.status || '1'
    });

    this.tenders.clear();
    (data.tenders || []).forEach((tender: any) => this.addTender(tender));
  }

  get tenders(): UntypedFormArray {
    return this.form.get('tenders') as UntypedFormArray;
  }

  addTender(tender?: any) {
    this.tenders.push(this.fb.group({
      name: tender?.name || '',
      date: tender?.date || '',
      document_url: tender?.document_url || '',
      view_url: tender?.view_url || '',
      download_url: tender?.download_url || '',
      sort_order: tender?.sort_order || 0
    }));
  }

  removeTender(index: number) {
    this.tenders.removeAt(index);
  }

  save() {
    const data = this.form.value;
    data.tenders_id = this.existingId || '';
    data.loggedin_id = this.authService.getLoggedInID();
    data.status = data.status || '1';
    this.cmsService.saveTenders(data);
  }

  ngOnDestroy() {
    if (this.subscription) {
      this.subscription.unsubscribe();
    }
  }
}
